"""Generated by w2a — scheduled_watcher pattern for "Support Ticket Triage and Reporting"."""

from __future__ import annotations

from crewai import Agent, Crew, Process, Task

from config import build_llm
from tools import ALL_TOOLS

_llm = build_llm()

agent_triage_agent = Agent(
    role='Ticket Classifier',
    goal='Read incoming tickets, label them by category, and detect urgent issues.',
    backstory='You are a meticulous operations specialist with a deep understanding of support ticket workflows. Your expertise lies in parsing incoming zendesk content to accurately categorize issues and identify critical blockers that require immediate attention.',
    tools=ALL_TOOLS,
    llm=_llm,
    verbose=True,
)
agent_alert_agent = Agent(
    role='On-Call Notifier',
    goal='Trigger immediate alerts for high-priority issues via PagerDuty.',
    backstory='You are a highly responsive on-call coordinator dedicated to minimizing downtime for engineering staff. You monitor prioritized flows to ensure that any urgent ticket reaching the system triggers a direct alert to the appropriate personnel.',
    tools=ALL_TOOLS,
    llm=_llm,
    verbose=True,
)
agent_reporter_agent = Agent(
    role='Operations Analyst',
    goal='Compile a weekly summary of ticket trends and volume.',
    backstory='You are a data-driven operations analyst focused on long-term support health and trend identification. You excel at synthesizing raw ticket data into a comprehensive weekly analytical summary that informs business decisions.',
    tools=ALL_TOOLS,
    llm=_llm,
    verbose=True,
)


task_classify_ticket = Task(
    description='Analyze the text of the incoming zendesk ticket to determine its category as bug, billing, or question. Evaluate the content for specific urgency keywords to output a label and a boolean status for the triage process.\n\nActual ticket text to analyze:\n{input}',
    expected_output='Category label and an urgency status (boolean).',
    agent=agent_triage_agent,
)
task_generate_weekly_report = Task(
    description='Gather all support ticket data recorded over the past seven days to analyze volume and category distribution. Produce a weekly analytical summary document that highlights identified trends and counts of bugs, billing requests, and general questions.',
    expected_output='A weekly summary document showing counts of bugs, billing, and questions with noted spikes.',
    agent=agent_reporter_agent,
)
task_trigger_alert = Task(
    description='Receive the category label and urgency status from the triage process to decide if an action is required. If the status is urgent, execute a notification via the external system to alert the on-call staff and return a confirmation message.',
    expected_output='Confirmation of PagerDuty alert if triggered.',
    agent=agent_alert_agent,
    context=[task_classify_ticket],
)


def build_crew() -> Crew:
    return Crew(
        agents=[agent_triage_agent, agent_alert_agent, agent_reporter_agent],
        tasks=[task_classify_ticket, task_generate_weekly_report, task_trigger_alert],
        process=Process.sequential,
        verbose=True,
    )


def run_once(inputs: dict | None = None):
    """Execute one poll -> detect -> notify pass. Called in a loop by main.py."""
    crew = build_crew()
    return crew.kickoff(inputs=inputs or {})
